import re

def replace_emojis_in_file(filepath, replacements):
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    for emo, svg in replacements.items():
        content = content.replace(emo, svg)

    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(content)

